sql:
SELECT import_date, import_source
FROM data_import_logs
WHERE measurement_id = 1;

external_knowledge:
; A validated measurement refers to a measurement with 'validated' status; 
; The "most recent validated measurement value" refers to the measurement with the highest timestamp; 
; A measurement is considered "recent" if it has the highest timestamp and row number (rn) equals 1; 
; The "most recent access" refers to the access log with the highest access date for a given measurement; 
; The "metadata" refers to additional information about each measurement.

sql:
SELECT timestamp, value, confidence_level, COUNT(*) OVER () as total_measurements
FROM measurements
WHERE confidence_level > 0.75;

external_knowledge:
High Confidence Measurement: refers to the measurement with the highest confidence level within each station ID and parameter ID partition;
Above Average Confidence: refers to the measurements with confidence levels higher than the average confidence level within each station ID and parameter ID partition;
Below Average Confidence: refers to the measurements with confidence levels lower than the average confidence level within each station ID and parameter ID partition.

sql:
SELECT export_date, export_format
FROM data_export_logs
WHERE export_date = (SELECT MAX(export_date) FROM data_export_logs);
